```javascript
function isPrime(num) {
  if (num <= 1) return false; // Not a prime number
  if (num <= 3) return true; // 2 and 3 are prime numbers
  for (let i = 2; i <= Math.sqrt(num); i++) {
    if (num % i === 0) return false;
  }
  return true;
}

function checkPrimesInArray(arr) {
  if (arr.length !== 5) throw new Error("Input array must have exactly 5 numbers");
  for (let num of arr) {
    if (isPrime(num)) console.log(num);
  }
}

