Here is a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <sstream>

int main() {
    std::string filePath = "input.txt"; // Replace with your file path
    std::string searchWord = "word"; // Replace with the word to search for
    std::ifstream file(filePath);
    std::string line;
    int count = 0;

    if (file.is_open()) {
        while (getline(file, line)) {
            std::istringstream iss(line);
            std::string word;
            while (iss >> word) {
                if (word == searchWord) {
                    count++;
                }
            }
            iss.clear();
        }
        file.close();
    } else {
        std::cerr << "Unable to open file: " << filePath << std::endl;
        return 1;
    }

    std::cout << "Number of occurrences of \"" << searchWord << "\" in the file: " << count << std::endl;

    return 0;
}
```

Replace `input.txt` with the path to your text file and `word` with the word you want to search for. This program uses standard input/output streams and string streams to read the file line by line and word by word. It keeps a running count of the number of occurrences of the search word in each line.
